/* ============================================================
   DESIGN SYSTEM – HOUSEKEEPING QR REPORT
   Palette: Clean white + #4A90FF blue + soft grays
   Font: Nunito (rounded, friendly, large-print friendly)
   ============================================================ */

/* ---- Reset & Base ---- */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --clr-primary:    #4A90FF;
  --clr-primary-dk: #3478e6;
  --clr-bg-start:   #F8F9FB;
  --clr-bg-end:     #FFFFFF;
  --clr-card-main:  #E8F4FF;
  --clr-card-white: #FFFFFF;
  --clr-text-head:  #111111;
  --clr-text-body:  #333333;
  --clr-text-cap:   #6B7280;
  --clr-border:     #E2E8F0;
  --clr-success:    #22C55E;
  --clr-error:      #EF4444;

  --radius-card-lg: 20px;
  --radius-card-md: 16px;
  --radius-thumb:   14px;
  --radius-btn:     26px;

  --shadow-card:  0 8px 24px rgba(74,144,255,0.15);
  --shadow-btn:   0 4px 14px rgba(74,144,255,0.35);
  --shadow-thumb: 0 2px 8px rgba(0,0,0,0.12);

  --px: 16px;    /* horizontal padding */
  --gap-section: 24px;
  --gap-card:    16px;

  --font: 'Nunito', 'Helvetica Neue', Arial, sans-serif;
}

html, body {
  height: 100%;
  overflow: hidden;
  font-family: var(--font);
  font-size: 16px;
  color: var(--clr-text-body);
  background: var(--clr-bg-start);
  -webkit-font-smoothing: antialiased;
  -webkit-tap-highlight-color: transparent;
  touch-action: manipulation;
}

/* ============================================================
   SCREEN SYSTEM
   ============================================================ */
.screen {
  position: fixed;
  inset: 0;
  background: linear-gradient(160deg, var(--clr-bg-start) 0%, var(--clr-bg-end) 100%);
  transform: translateX(100%);
  transition: transform 300ms cubic-bezier(0.4, 0, 0.2, 1);
  z-index: 1;
  will-change: transform;
}
.screen.active {
  transform: translateX(0);
}
.screen.slide-out {
  transform: translateX(-30%);
  opacity: 0.6;
  transition: transform 300ms cubic-bezier(0.4, 0, 0.2, 1),
              opacity 300ms ease;
}

.screen-inner {
  display: flex;
  flex-direction: column;
  height: 100%;
  padding: 0;
  overflow: hidden;
}
.screen-inner--scroll {
  overflow-y: auto;
  -webkit-overflow-scrolling: touch;
}
.screen-inner--center {
  align-items: center;
  justify-content: space-between;
}

/* ============================================================
   HEADER
   ============================================================ */
.screen-header {
  padding: 52px var(--px) 20px;
  background: transparent;
  flex-shrink: 0;
}
.screen-header--room {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 52px var(--px) 12px;
}

.app-logo {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 20px;
}
.app-logo__text {
  font-size: 15px;
  font-weight: 700;
  color: var(--clr-primary);
  letter-spacing: 0.3px;
}

.screen-header__title {
  font-size: 26px;
  font-weight: 800;
  color: var(--clr-text-head);
  line-height: 1.2;
  margin-bottom: 6px;
}
.screen-header__subtitle {
  font-size: 14px;
  font-weight: 400;
  color: var(--clr-text-cap);
  line-height: 1.5;
}

.btn-back {
  width: 40px;
  height: 40px;
  border: none;
  background: var(--clr-card-white);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: 0 2px 8px rgba(0,0,0,0.1);
  cursor: pointer;
  flex-shrink: 0;
  transition: transform 150ms ease, box-shadow 150ms ease;
}
.btn-back:active { transform: scale(0.94); }

/* ============================================================
   ROOM BADGE
   ============================================================ */
.room-badge {
  background: var(--clr-primary);
  color: white;
  font-size: 16px;
  font-weight: 800;
  letter-spacing: 1.5px;
  padding: 8px 20px;
  border-radius: var(--radius-btn);
  box-shadow: var(--shadow-btn);
}

/* ============================================================
   PHOTO COUNTER (screen 2)
   ============================================================ */
.photo-counter {
  display: flex;
  align-items: center;
  gap: 2px;
  font-size: 18px;
  font-weight: 700;
  color: var(--clr-text-head);
}
.photo-counter__sep { color: var(--clr-text-cap); }

/* ============================================================
   SCREEN MAIN
   ============================================================ */
.screen-main {
  flex: 1;
  padding: 0 var(--px);
  overflow: hidden;
}
.report-main {
  overflow-y: auto;
  -webkit-overflow-scrolling: touch;
  padding-bottom: 16px;
  display: flex;
  flex-direction: column;
  gap: var(--gap-card);
}

/* ============================================================
   QR SCANNER  (Screen 1)
   ============================================================ */
.qr-wrapper {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 20px;
  padding-top: 12px;
}

.qr-frame {
  position: relative;
  width: 100%;
  max-width: 320px;
  aspect-ratio: 3/4;
  background: #000;
  border-radius: 20px;
  overflow: hidden;
  box-shadow: 0 16px 48px rgba(0,0,0,0.25);
}

#qr-video {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

/* Subtle blue overlay */
.qr-frame::before {
  content: '';
  position: absolute;
  inset: 0;
  background: rgba(74, 144, 255, 0.08);
  pointer-events: none;
  z-index: 2;
}

/* Corner brackets */
.qr-corner {
  position: absolute;
  width: 28px;
  height: 28px;
  z-index: 3;
}
.qr-corner--tl { top: 16px; left: 16px;
  border-top: 3px solid white; border-left: 3px solid white;
  border-radius: 6px 0 0 0; }
.qr-corner--tr { top: 16px; right: 16px;
  border-top: 3px solid white; border-right: 3px solid white;
  border-radius: 0 6px 0 0; }
.qr-corner--bl { bottom: 16px; left: 16px;
  border-bottom: 3px solid white; border-left: 3px solid white;
  border-radius: 0 0 0 6px; }
.qr-corner--br { bottom: 16px; right: 16px;
  border-bottom: 3px solid white; border-right: 3px solid white;
  border-radius: 0 0 6px 0; }

/* Scan line animation */
.qr-scanline {
  position: absolute;
  left: 12px; right: 12px;
  height: 2px;
  background: linear-gradient(90deg, transparent, #4A90FF, transparent);
  z-index: 4;
  top: 10%;
  animation: scanMove 2.4s ease-in-out infinite;
  box-shadow: 0 0 8px rgba(74,144,255,0.8);
}
@keyframes scanMove {
  0%   { top: 10%; opacity: 0.7; }
  50%  { top: 85%; opacity: 1; }
  100% { top: 10%; opacity: 0.7; }
}

/* Pulse ring around corners when scanning */
.qr-frame.scanning .qr-corner {
  animation: cornerPulse 1.2s ease-in-out infinite alternate;
}
@keyframes cornerPulse {
  from { opacity: 0.7; }
  to   { opacity: 1; filter: drop-shadow(0 0 4px rgba(74,144,255,0.9)); }
}

.qr-hint {
  font-size: 13px;
  font-weight: 600;
  color: var(--clr-text-cap);
  text-align: center;
  max-width: 280px;
  line-height: 1.6;
}

/* ============================================================
   CAMERA (Screen 2)
   ============================================================ */
.camera-label {
  padding: 0 var(--px) 10px;
  flex-shrink: 0;
}
.camera-label__text {
  font-size: 14px;
  font-weight: 600;
  color: var(--clr-text-cap);
}

.camera-main {
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding-bottom: 0;
}

.camera-viewport {
  position: relative;
  flex: 1;
  background: #000;
  border-radius: var(--radius-card-lg);
  overflow: hidden;
  box-shadow: 0 8px 32px rgba(0,0,0,0.25);
  min-height: 0;
}

#camera-video {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}
.camera-overlay {
  position: absolute;
  inset: 0;
  border: 2px solid rgba(255,255,255,0.15);
  border-radius: var(--radius-card-lg);
  pointer-events: none;
}

/* Thumbnail strip */
.thumbnail-row {
  display: flex;
  gap: 10px;
  overflow-x: auto;
  padding: 2px 0;
  flex-shrink: 0;
  min-height: 68px;
  -webkit-overflow-scrolling: touch;
  scrollbar-width: none;
}
.thumbnail-row::-webkit-scrollbar { display: none; }

.thumb {
  position: relative;
  width: 64px;
  height: 64px;
  flex-shrink: 0;
  border-radius: var(--radius-thumb);
  overflow: hidden;
  box-shadow: var(--shadow-thumb);
  animation: thumbIn 200ms cubic-bezier(0.34,1.56,0.64,1);
}
@keyframes thumbIn {
  from { transform: scale(0.6); opacity: 0; }
  to   { transform: scale(1);   opacity: 1; }
}
.thumb img {
  width: 100%; height: 100%;
  object-fit: cover; display: block;
}
.thumb__del {
  position: absolute;
  top: 4px; right: 4px;
  width: 20px; height: 20px;
  background: rgba(0,0,0,0.55);
  border: none; border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  cursor: pointer; padding: 0;
  transition: background 150ms;
}
.thumb__del:active { background: var(--clr-error); }
.thumb__del svg { display: block; }

/* Shutter */
.camera-footer {
  padding: 12px var(--px) max(24px, env(safe-area-inset-bottom));
  flex-direction: column;
  gap: 12px;
}
.shutter-row {
  display: flex;
  justify-content: center;
}
.shutter-btn {
  position: relative;
  width: 72px; height: 72px;
  border: none;
  background: transparent;
  cursor: pointer;
  padding: 0;
  display: flex; align-items: center; justify-content: center;
  transition: transform 150ms ease;
}
.shutter-btn:active { transform: scale(0.92); }
.shutter-btn__ring {
  position: absolute;
  width: 72px; height: 72px;
  border-radius: 50%;
  border: 4px solid white;
  box-shadow: 0 0 0 2px rgba(255,255,255,0.3), 0 4px 16px rgba(0,0,0,0.3);
}
.shutter-btn__dot {
  width: 52px; height: 52px;
  background: white;
  border-radius: 50%;
  box-shadow: 0 2px 8px rgba(0,0,0,0.2);
  transition: background 150ms;
}
.shutter-btn:active .shutter-btn__dot { background: #e0e0e0; }

/* ============================================================
   CARDS
   ============================================================ */
.card {
  border-radius: var(--radius-card-lg);
  padding: 16px;
}
.card--main {
  background: var(--clr-card-main);
  box-shadow: var(--shadow-card);
}
.card--secondary {
  background: var(--clr-card-white);
  border-radius: var(--radius-card-md);
  padding: 12px 16px;
  border: 1.5px solid var(--clr-border);
}
.card--voice {
  padding: 16px 16px 20px;
}

.card__label {
  display: flex;
  align-items: center;
  gap: 7px;
  font-size: 14px;
  font-weight: 700;
  color: var(--clr-text-head);
  margin-bottom: 14px;
}
.card__label-muted { color: var(--clr-text-cap); font-weight: 600; }
.card__count {
  margin-left: auto;
  font-size: 12px;
  font-weight: 600;
  color: var(--clr-primary);
  background: rgba(74,144,255,0.12);
  padding: 2px 10px;
  border-radius: 99px;
}

/* Photo list in report screen */
.photo-list {
  display: flex;
  gap: 10px;
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
  scrollbar-width: none;
}
.photo-list::-webkit-scrollbar { display: none; }
.photo-list .thumb {
  width: 80px; height: 80px;
}

/* ============================================================
   VOICE RECORDER
   ============================================================ */
.voice-record {
  display: flex;
  align-items: center;
  gap: 20px;
  margin-bottom: 16px;
}

.mic-btn {
  position: relative;
  width: 72px; height: 72px;
  flex-shrink: 0;
  background: var(--clr-primary);
  border: none; border-radius: 50%;
  cursor: pointer;
  display: flex; align-items: center; justify-content: center;
  box-shadow: var(--shadow-btn);
  transition: transform 150ms ease, background 150ms ease;
}
.mic-btn:active { transform: scale(0.94); }
.mic-btn.recording {
  background: var(--clr-error);
  animation: micPulse 1s ease-in-out infinite;
}
@keyframes micPulse {
  0%,100% { box-shadow: 0 0 0 0 rgba(239,68,68,0.5); }
  50%      { box-shadow: 0 0 0 14px rgba(239,68,68,0); }
}

.mic-btn__ripple {
  position: absolute;
  inset: -10px;
  border-radius: 50%;
  border: 2px solid rgba(74,144,255,0.4);
  opacity: 0;
}
.mic-btn.recording .mic-btn__ripple {
  animation: rippleOut 1s ease-in-out infinite;
}
@keyframes rippleOut {
  0%   { transform: scale(0.7); opacity: 0.7; }
  100% { transform: scale(1.3); opacity: 0; }
}

.mic-icon { display: block; }

.voice-status { flex: 1; }
.voice-status__label {
  font-size: 15px;
  font-weight: 700;
  color: var(--clr-text-head);
  display: block;
}

/* Animated wave bars */
.voice-wave {
  display: flex;
  align-items: center;
  gap: 4px;
  height: 28px;
  margin-top: 6px;
}
.voice-wave span {
  display: block;
  width: 4px;
  background: var(--clr-primary);
  border-radius: 2px;
  animation: waveBar 0.8s ease-in-out infinite;
}
.voice-wave span:nth-child(1) { height: 12px; animation-delay: 0s; }
.voice-wave span:nth-child(2) { height: 22px; animation-delay: 0.1s; }
.voice-wave span:nth-child(3) { height: 28px; animation-delay: 0.2s; }
.voice-wave span:nth-child(4) { height: 22px; animation-delay: 0.3s; }
.voice-wave span:nth-child(5) { height: 12px; animation-delay: 0.4s; }
@keyframes waveBar {
  0%,100% { transform: scaleY(0.5); }
  50%     { transform: scaleY(1.2); }
}

/* Transcript */
.transcript-box { }
.transcript-input {
  width: 100%;
  border: 1.5px solid var(--clr-border);
  border-radius: 12px;
  padding: 12px 14px;
  font-family: var(--font);
  font-size: 14px;
  font-weight: 500;
  color: var(--clr-text-body);
  line-height: 1.6;
  resize: none;
  background: white;
  transition: border-color 200ms;
  outline: none;
}
.transcript-input:focus { border-color: var(--clr-primary); }

/* ============================================================
   BUTTONS
   ============================================================ */
.screen-footer {
  flex-shrink: 0;
  padding: 16px var(--px) max(24px, env(safe-area-inset-bottom));
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  height: 52px;
  border: none;
  border-radius: var(--radius-btn);
  font-family: var(--font);
  font-size: 16px;
  font-weight: 700;
  cursor: pointer;
  transition: transform 150ms ease, filter 150ms ease, box-shadow 150ms ease;
  -webkit-tap-highlight-color: transparent;
  width: 100%;
}
.btn:active {
  transform: scale(0.98);
  filter: brightness(0.9);
}

.btn--primary {
  background: var(--clr-primary);
  color: white;
  box-shadow: var(--shadow-btn);
  letter-spacing: 0.5px;
}
.btn--primary:active { background: var(--clr-primary-dk); }

.btn--secondary {
  background: rgba(74,144,255,0.1);
  color: var(--clr-primary);
  font-size: 15px;
}

.btn--submit {
  font-size: 17px;
  font-weight: 800;
  letter-spacing: 1px;
}

.sticky-footer {
  position: sticky;
  bottom: 0;
  background: linear-gradient(180deg, transparent 0%, var(--clr-bg-end) 30%);
  padding: 20px var(--px) max(24px, env(safe-area-inset-bottom));
  flex-shrink: 0;
}

/* ============================================================
   SUCCESS SCREEN
   ============================================================ */
.success-main {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-align: center;
  padding: 32px var(--px);
  flex: 1;
  gap: 0;
}

.success-icon-wrap {
  position: relative;
  width: 120px; height: 120px;
  margin-bottom: 28px;
}
.success-ring {
  position: absolute;
  border-radius: 50%;
  top: 50%; left: 50%;
  transform: translate(-50%, -50%);
  background: rgba(74,144,255,0.12);
  animation: successRing 0.6s cubic-bezier(0.34,1.56,0.64,1) both;
}
.success-ring--outer {
  width: 120px; height: 120px;
  animation-delay: 0.1s;
}
.success-ring--inner {
  width: 90px; height: 90px;
  background: rgba(74,144,255,0.18);
  animation-delay: 0.2s;
}
.success-icon {
  position: absolute;
  top: 50%; left: 50%;
  transform: translate(-50%, -50%);
  width: 68px; height: 68px;
  background: var(--clr-primary);
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  box-shadow: var(--shadow-btn);
  animation: successPop 0.5s cubic-bezier(0.34,1.56,0.64,1) 0.2s both;
}
@keyframes successRing {
  from { transform: translate(-50%,-50%) scale(0.3); opacity: 0; }
  to   { transform: translate(-50%,-50%) scale(1);   opacity: 1; }
}
@keyframes successPop {
  from { transform: translate(-50%,-50%) scale(0.4); opacity: 0; }
  to   { transform: translate(-50%,-50%) scale(1);   opacity: 1; }
}

.success-title {
  font-size: 22px;
  font-weight: 800;
  color: var(--clr-text-head);
  line-height: 1.3;
  margin-bottom: 8px;
}
.success-sub {
  font-size: 15px;
  font-weight: 600;
  color: var(--clr-primary);
  margin-bottom: 4px;
}
.success-time {
  font-size: 13px;
  font-weight: 400;
  color: var(--clr-text-cap);
  margin-bottom: 28px;
}
.success-divider {
  width: 48px; height: 3px;
  background: var(--clr-border);
  border-radius: 2px;
  margin: 0 auto 24px;
}
.success-count-row {
  display: flex;
  align-items: center;
  gap: 32px;
}
.success-stat {
  display: flex; flex-direction: column; align-items: center; gap: 4px;
}
.success-stat__num {
  font-size: 28px;
  font-weight: 900;
  color: var(--clr-text-head);
}
.success-stat__label {
  font-size: 12px;
  font-weight: 600;
  color: var(--clr-text-cap);
  text-transform: uppercase;
  letter-spacing: 0.8px;
}
.success-stat__sep {
  width: 1px; height: 40px;
  background: var(--clr-border);
}

.success-redirect-hint {
  text-align: center;
  font-size: 13px;
  color: var(--clr-text-cap);
  font-weight: 500;
}

/* ============================================================
   TOAST
   ============================================================ */
.toast {
  position: fixed;
  bottom: 32px; left: 50%;
  transform: translateX(-50%) translateY(80px);
  background: rgba(17,17,17,0.88);
  color: white;
  padding: 12px 20px;
  border-radius: 99px;
  font-size: 14px;
  font-weight: 600;
  white-space: nowrap;
  z-index: 9999;
  transition: transform 300ms cubic-bezier(0.34,1.56,0.64,1), opacity 300ms ease;
  opacity: 0;
  pointer-events: none;
  backdrop-filter: blur(8px);
}
.toast.show {
  transform: translateX(-50%) translateY(0);
  opacity: 1;
}

/* Error toast inline */
.error-toast {
  background: rgba(239,68,68,0.1);
  border: 1.5px solid rgba(239,68,68,0.3);
  color: var(--clr-error);
  padding: 10px 14px;
  border-radius: 12px;
  font-size: 13px;
  font-weight: 600;
  margin-bottom: 8px;
}

/* ============================================================
   LOADING SPINNER (inline)
   ============================================================ */
.spinner {
  display: inline-block;
  width: 18px; height: 18px;
  border: 2.5px solid rgba(255,255,255,0.4);
  border-top-color: white;
  border-radius: 50%;
  animation: spin 0.7s linear infinite;
  vertical-align: middle;
}
@keyframes spin { to { transform: rotate(360deg); } }

/* ============================================================
   UPLOAD PROGRESS
   ============================================================ */
.upload-overlay {
  position: absolute;
  inset: 0;
  background: rgba(74,144,255,0.75);
  display: flex; align-items: center; justify-content: center;
  border-radius: var(--radius-thumb);
}
.upload-overlay .spinner {
  width: 22px; height: 22px;
}

/* ============================================================
   DESIGN SYSTEM – HOUSEKEEPING QR REPORT
   Palette: Clean white + #4A90FF blue + soft grays
   Font: Nunito (rounded, friendly, large-print friendly)
   ============================================================ */

/* ---- Reset & Base ---- */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --clr-primary:    #4A90FF;
  --clr-primary-dk: #3478e6;
  --clr-bg-start:   #F8F9FB;
  --clr-bg-end:     #FFFFFF;
  --clr-card-main:  #E8F4FF;
  --clr-card-white: #FFFFFF;
  --clr-text-head:  #111111;
  --clr-text-body:  #333333;
  --clr-text-cap:   #6B7280;
  --clr-border:     #E2E8F0;
  --clr-success:    #22C55E;
  --clr-error:      #EF4444;

  --radius-card-lg: 20px;
  --radius-card-md: 16px;
  --radius-thumb:   14px;
  --radius-btn:     26px;

  --shadow-card:  0 8px 24px rgba(74,144,255,0.15);
  --shadow-btn:   0 4px 14px rgba(74,144,255,0.35);
  --shadow-thumb: 0 2px 8px rgba(0,0,0,0.12);

  --px: 16px;
  --gap-section: 24px;
  --gap-card:    16px;

  --font: 'Nunito', 'Helvetica Neue', Arial, sans-serif;
}

html, body {
  height: 100%;
  overflow: hidden;
  font-family: var(--font);
  font-size: 16px;
  color: var(--clr-text-body);
  background: var(--clr-bg-start);
  -webkit-font-smoothing: antialiased;
  -webkit-tap-highlight-color: transparent;
  touch-action: manipulation;
}

/* ============================================================
   SCREEN SYSTEM
   ============================================================ */
.screen {
  position: fixed;
  inset: 0;
  background: linear-gradient(160deg, var(--clr-bg-start) 0%, var(--clr-bg-end) 100%);
  transform: translateX(100%);
  transition: transform 300ms cubic-bezier(0.4, 0, 0.2, 1);
  z-index: 1;
  will-change: transform;
}
.screen.active {
  transform: translateX(0);
  z-index: 2;
}
.screen.slide-out {
  transform: translateX(-30%);
  opacity: 0.6;
  transition: transform 300ms cubic-bezier(0.4, 0, 0.2, 1),
              opacity 300ms ease;
  z-index: 1;
}

.screen-inner {
  display: flex;
  flex-direction: column;
  height: 100%;
  overflow: hidden;
}
.screen-inner--scroll {
  overflow-y: auto;
  -webkit-overflow-scrolling: touch;
}
.screen-inner--center {
  justify-content: space-between;
}

/* ============================================================
   HEADER
   ============================================================ */
.screen-header {
  padding: 52px var(--px) 20px;
  background: transparent;
  flex-shrink: 0;
}
.screen-header--room {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 52px var(--px) 12px;
}

.app-logo {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 20px;
}
.app-logo__text {
  font-size: 15px;
  font-weight: 700;
  color: var(--clr-primary);
  letter-spacing: 0.3px;
}

.screen-header__title {
  font-size: 26px;
  font-weight: 800;
  color: var(--clr-text-head);
  line-height: 1.2;
  margin-bottom: 6px;
}
.screen-header__subtitle {
  font-size: 14px;
  font-weight: 400;
  color: var(--clr-text-cap);
  line-height: 1.5;
}

.btn-back {
  width: 40px;
  height: 40px;
  border: none;
  background: var(--clr-card-white);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: 0 2px 8px rgba(0,0,0,0.1);
  cursor: pointer;
  flex-shrink: 0;
  transition: transform 150ms ease;
}
.btn-back:active { transform: scale(0.94); }

/* ============================================================
   ROOM BADGE
   ============================================================ */
.room-badge {
  background: var(--clr-primary);
  color: white;
  font-size: 16px;
  font-weight: 800;
  letter-spacing: 1.5px;
  padding: 8px 20px;
  border-radius: var(--radius-btn);
  box-shadow: var(--shadow-btn);
}

/* ============================================================
   PHOTO COUNTER
   ============================================================ */
.photo-counter {
  display: flex;
  align-items: center;
  gap: 2px;
  font-size: 18px;
  font-weight: 700;
  color: var(--clr-text-head);
}
.photo-counter__sep { color: var(--clr-text-cap); }

/* ============================================================
   SCREEN MAIN
   ============================================================ */
.screen-main {
  flex: 1;
  padding: 0 var(--px);
  overflow: hidden;
}
.report-main {
  overflow-y: auto;
  -webkit-overflow-scrolling: touch;
  padding-bottom: 16px;
  display: flex;
  flex-direction: column;
  gap: var(--gap-card);
}

/* ============================================================
   QR SCANNER
   ============================================================ */
.qr-wrapper {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 20px;
  padding-top: 12px;
}

.qr-frame {
  position: relative;
  width: 100%;
  max-width: 300px;
  aspect-ratio: 3/4;
  background: #000;
  border-radius: 20px;
  overflow: hidden;
  box-shadow: 0 16px 48px rgba(0,0,0,0.25);
}

#qr-video {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

.qr-frame::before {
  content: '';
  position: absolute;
  inset: 0;
  background: rgba(74, 144, 255, 0.08);
  pointer-events: none;
  z-index: 2;
}

.qr-corner {
  position: absolute;
  width: 28px;
  height: 28px;
  z-index: 3;
}
.qr-corner--tl { top: 16px; left: 16px;
  border-top: 3px solid white; border-left: 3px solid white;
  border-radius: 6px 0 0 0; }
.qr-corner--tr { top: 16px; right: 16px;
  border-top: 3px solid white; border-right: 3px solid white;
  border-radius: 0 6px 0 0; }
.qr-corner--bl { bottom: 16px; left: 16px;
  border-bottom: 3px solid white; border-left: 3px solid white;
  border-radius: 0 0 0 6px; }
.qr-corner--br { bottom: 16px; right: 16px;
  border-bottom: 3px solid white; border-right: 3px solid white;
  border-radius: 0 0 6px 0; }

.qr-scanline {
  position: absolute;
  left: 12px; right: 12px;
  height: 2px;
  background: linear-gradient(90deg, transparent, #4A90FF, transparent);
  z-index: 4;
  top: 10%;
  animation: scanMove 2.4s ease-in-out infinite;
  box-shadow: 0 0 8px rgba(74,144,255,0.8);
}
@keyframes scanMove {
  0%   { top: 10%; opacity: 0.7; }
  50%  { top: 85%; opacity: 1; }
  100% { top: 10%; opacity: 0.7; }
}

.qr-frame.scanning .qr-corner {
  animation: cornerPulse 1.2s ease-in-out infinite alternate;
}
@keyframes cornerPulse {
  from { opacity: 0.7; }
  to   { opacity: 1; filter: drop-shadow(0 0 4px rgba(74,144,255,0.9)); }
}

.qr-hint {
  font-size: 13px;
  font-weight: 600;
  color: var(--clr-text-cap);
  text-align: center;
  max-width: 280px;
  line-height: 1.6;
}

/* ============================================================
   CAMERA
   ============================================================ */
.camera-label {
  padding: 0 var(--px) 10px;
  flex-shrink: 0;
}
.camera-label__text {
  font-size: 14px;
  font-weight: 600;
  color: var(--clr-text-cap);
}

.camera-main {
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding-bottom: 0;
}

.camera-viewport {
  position: relative;
  flex: 1;
  background: #000;
  border-radius: var(--radius-card-lg);
  overflow: hidden;
  box-shadow: 0 8px 32px rgba(0,0,0,0.25);
  min-height: 0;
}

#camera-video {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}
.camera-overlay {
  position: absolute;
  inset: 0;
  border: 2px solid rgba(255,255,255,0.15);
  border-radius: var(--radius-card-lg);
  pointer-events: none;
}

.thumbnail-row {
  display: flex;
  gap: 10px;
  overflow-x: auto;
  padding: 2px 0;
  flex-shrink: 0;
  min-height: 68px;
  -webkit-overflow-scrolling: touch;
  scrollbar-width: none;
}
.thumbnail-row::-webkit-scrollbar { display: none; }

.thumb {
  position: relative;
  width: 64px;
  height: 64px;
  flex-shrink: 0;
  border-radius: var(--radius-thumb);
  overflow: hidden;
  box-shadow: var(--shadow-thumb);
  animation: thumbIn 200ms cubic-bezier(0.34,1.56,0.64,1);
}
@keyframes thumbIn {
  from { transform: scale(0.6); opacity: 0; }
  to   { transform: scale(1);   opacity: 1; }
}
.thumb img {
  width: 100%; height: 100%;
  object-fit: cover; display: block;
}
.thumb__del {
  position: absolute;
  top: 4px; right: 4px;
  width: 20px; height: 20px;
  background: rgba(0,0,0,0.55);
  border: none; border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  cursor: pointer; padding: 0;
  transition: background 150ms;
}
.thumb__del:active { background: var(--clr-error); }

/* ============================================================
   FOOTER / BUTTONS
   ============================================================ */
.screen-footer {
  flex-shrink: 0;
  padding: 16px var(--px) max(24px, env(safe-area-inset-bottom));
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.camera-footer {
  padding: 12px var(--px) max(24px, env(safe-area-inset-bottom));
  flex-direction: column;
  gap: 12px;
}

.shutter-row {
  display: flex;
  justify-content: center;
}
.shutter-btn {
  position: relative;
  width: 72px; height: 72px;
  border: none;
  background: transparent;
  cursor: pointer;
  padding: 0;
  display: flex; align-items: center; justify-content: center;
  transition: transform 150ms ease;
}
.shutter-btn:active { transform: scale(0.92); }
.shutter-btn__ring {
  position: absolute;
  width: 72px; height: 72px;
  border-radius: 50%;
  border: 4px solid white;
  box-shadow: 0 0 0 2px rgba(255,255,255,0.3), 0 4px 16px rgba(0,0,0,0.3);
}
.shutter-btn__dot {
  width: 52px; height: 52px;
  background: white;
  border-radius: 50%;
  box-shadow: 0 2px 8px rgba(0,0,0,0.2);
  transition: background 150ms;
}
.shutter-btn:active .shutter-btn__dot { background: #e0e0e0; }

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  height: 52px;
  border: none;
  border-radius: var(--radius-btn);
  font-family: var(--font);
  font-size: 16px;
  font-weight: 700;
  cursor: pointer;
  transition: transform 150ms ease, filter 150ms ease;
  -webkit-tap-highlight-color: transparent;
  width: 100%;
}
.btn:active {
  transform: scale(0.98);
  filter: brightness(0.9);
}
.btn--primary {
  background: var(--clr-primary);
  color: white;
  box-shadow: var(--shadow-btn);
  letter-spacing: 0.5px;
}
.btn--secondary {
  background: rgba(74,144,255,0.1);
  color: var(--clr-primary);
  font-size: 15px;
}
.btn--submit {
  font-size: 17px;
  font-weight: 800;
  letter-spacing: 1px;
}
.btn:disabled {
  opacity: 0.6;
  pointer-events: none;
}

.sticky-footer {
  position: sticky;
  bottom: 0;
  background: linear-gradient(180deg, transparent 0%, var(--clr-bg-end) 30%);
  padding: 20px var(--px) max(24px, env(safe-area-inset-bottom));
  flex-shrink: 0;
}

/* ============================================================
   CARDS
   ============================================================ */
.card {
  border-radius: var(--radius-card-lg);
  padding: 16px;
}
.card--main {
  background: var(--clr-card-main);
  box-shadow: var(--shadow-card);
}
.card--secondary {
  background: var(--clr-card-white);
  border-radius: var(--radius-card-md);
  padding: 12px 16px;
  border: 1.5px solid var(--clr-border);
}
.card--voice {
  padding: 16px 16px 20px;
}

.card__label {
  display: flex;
  align-items: center;
  gap: 7px;
  font-size: 14px;
  font-weight: 700;
  color: var(--clr-text-head);
  margin-bottom: 14px;
}
.card__label-muted { color: var(--clr-text-cap); font-weight: 600; }
.card__count {
  margin-left: auto;
  font-size: 12px;
  font-weight: 600;
  color: var(--clr-primary);
  background: rgba(74,144,255,0.12);
  padding: 2px 10px;
  border-radius: 99px;
}

.photo-list {
  display: flex;
  gap: 10px;
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
  scrollbar-width: none;
}
.photo-list::-webkit-scrollbar { display: none; }
.photo-list .thumb {
  width: 80px; height: 80px;
}

/* ============================================================
   VOICE RECORDER
   ============================================================ */
.voice-record {
  display: flex;
  align-items: center;
  gap: 20px;
  margin-bottom: 16px;
}

.mic-btn {
  position: relative;
  width: 72px; height: 72px;
  flex-shrink: 0;
  background: var(--clr-primary);
  border: none; border-radius: 50%;
  cursor: pointer;
  display: flex; align-items: center; justify-content: center;
  box-shadow: var(--shadow-btn);
  transition: transform 150ms ease, background 150ms ease;
}
.mic-btn:active { transform: scale(0.94); }
.mic-btn.recording {
  background: var(--clr-error);
  animation: micPulse 1s ease-in-out infinite;
}
@keyframes micPulse {
  0%,100% { box-shadow: 0 0 0 0 rgba(239,68,68,0.5); }
  50%      { box-shadow: 0 0 0 14px rgba(239,68,68,0); }
}

.mic-btn__ripple {
