}

.success-icon-wrap {
  position: relative;
  width: 120px; height: 120px;
  margin-bottom: 28px;
}
.success-ring {
  position: absolute;
  border-radius: 50%;
  top: 50%; left: 50%;
  transform: translate(-50%, -50%);
