   DESIGN SYSTEM – HOUSEKEEPING QR REPORT
   Palette: Clean white + #4A90FF blue + soft grays
   Font: Nunito (rounded, friendly, large-print friendly)
   ============================================================ */

/* ---- Reset & Base ---- */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --clr-primary:    #4A90FF;
  --clr-primary-dk: #3478e6;
  --clr-bg-start:   #F8F9FB;
  --clr-bg-end:     #FFFFFF;
  --clr-card-main:  #E8F4FF;
  --clr-card-white: #FFFFFF;
  --clr-text-head:  #111111;
  --clr-text-body:  #333333;
  --clr-text-cap:   #6B7280;
  --clr-border:     #E2E8F0;
  --clr-success:    #22C55E;
  --clr-error:      #EF4444;

  --radius-card-lg: 20px;
  --radius-card-md: 16px;
  --radius-thumb:   14px;
  --radius-btn:     26px;

  --shadow-card:  0 8px 24px rgba(74,144,255,0.15);
  --shadow-btn:   0 4px 14px rgba(74,144,255,0.35);
  --shadow-thumb: 0 2px 8px rgba(0,0,0,0.12);

  --px: 16px;
  --gap-section: 24px;
  --gap-card:    16px;

  --font: 'Nunito', 'Helvetica Neue', Arial, sans-serif;
}

html, body {
  height: 100%;
  overflow: hidden;
  font-family: var(--font);
  font-size: 16px;
  color: var(--clr-text-body);
  background: var(--clr-bg-start);
  -webkit-font-smoothing: antialiased;
  -webkit-tap-highlight-color: transparent;
  touch-action: manipulation;
}

/* ============================================================
   SCREEN SYSTEM
   ============================================================ */
.screen {
  position: fixed;
  inset: 0;
  background: linear-gradient(160deg, var(--clr-bg-start) 0%, var(--clr-bg-end) 100%);
  transform: translateX(100%);
  transition: transform 300ms cubic-bezier(0.4, 0, 0.2, 1);
  z-index: 1;
  will-change: transform;
}
.screen.active {
  transform: translateX(0);
  z-index: 2;
}
.screen.slide-out {
  transform: translateX(-30%);
