.voice-wave span:nth-child(3) { height: 28px; animation-delay: 0.2s; }
.voice-wave span:nth-child(4) { height: 22px; animation-delay: 0.3s; }
.voice-wave span:nth-child(5) { height: 12px; animation-delay: 0.4s; }
@keyframes waveBar {
