/**
 * Housekeeping QR Report – Main App Logic
 * Screens: QR Scan → Camera Capture → Room Report → Success
 */

// ─── State ────────────────────────────────────────────────────────────────────
const state = {
  roomId: null,
  photos: [],          // { blob, dataUrl, s3Url }
  voiceText: '',
  isRecording: false,
  recognition: null,
  cameraStream: null,
  qrStream: null,
  qrScanInterval: null,
  redirectTimer: null,
};

// ─── DOM refs ─────────────────────────────────────────────────────────────────
const $  = id => document.getElementById(id);
const screens = {
  qr:      $('screen-qr'),
  camera:  $('screen-camera'),
  report:  $('screen-report'),
  success: $('screen-success'),
};

// ─── Screen navigation ────────────────────────────────────────────────────────
let currentScreen = 'qr';
function goTo(name, back = false) {
  const prev = screens[currentScreen];
  const next = screens[name];
  if (!next || name === currentScreen) return;

  if (back) {
    // Slide next in from left, push prev to right
    next.style.transform = 'translateX(-100%)';
    next.classList.add('active');
    requestAnimationFrame(() => {
      next.style.transition = 'transform 300ms cubic-bezier(0.4,0,0.2,1)';
      next.style.transform = 'translateX(0)';
      prev.style.transition = 'transform 300ms cubic-bezier(0.4,0,0.2,1)';
      prev.style.transform = 'translateX(100%)';
    });
    setTimeout(() => {
      prev.classList.remove('active');
      prev.style.transform = '';
      prev.style.transition = '';
      next.style.transition = '';
    }, 310);
  } else {
    prev.classList.add('slide-out');
    next.classList.add('active');
    setTimeout(() => {
      prev.classList.remove('active', 'slide-out');
      prev.style.transform = '';
    }, 310);
  }

  currentScreen = name;
}

// ─── Toast ────────────────────────────────────────────────────────────────────
let toastTimer;
function showToast(msg) {
  const el = $('toast');
  el.textContent = msg;
  el.classList.add('show');
  clearTimeout(toastTimer);
  toastTimer = setTimeout(() => el.classList.remove('show'), 2800);
}

function escapeHtml(text) {
  const d = document.createElement('div');
  d.textContent = String(text);
  return d.innerHTML;
}

// ─── QR SCAN SCREEN ───────────────────────────────────────────────────────────
async function startQrScan() {
  const video  = $('qr-video');
  const canvas = $('qr-canvas');
  const frame  = $('qr-frame');
  const btn    = $('btn-start-scan');

  btn.innerHTML = '<span class="spinner"></span> Đang mở camera…';
  btn.disabled = true;

  try {
    const stream = await navigator.mediaDevices.getUserMedia({
      video: { facingMode: 'environment', width: { ideal: 1280 }, height: { ideal: 960 } },
    });
    state.qrStream = stream;
    video.srcObject = stream;
    await video.play();

    frame.classList.add('scanning');
    btn.innerHTML = '⏹ Dừng quét';
    btn.disabled = false;
    btn.onclick = stopQrScan;

    const ctx = canvas.getContext('2d');
    state.qrScanInterval = setInterval(() => {
      if (video.readyState !== video.HAVE_ENOUGH_DATA) return;
      canvas.width  = video.videoWidth;
      canvas.height = video.videoHeight;
      ctx.drawImage(video, 0, 0);
      const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
      const code = jsQR(imgData.data, imgData.width, imgData.height, {
        inversionAttempts: 'dontInvert',
      });
      if (code && code.data) {
        handleQrResult(code.data);
      }
    }, 200);

  } catch (err) {
    console.error(err);
    btn.innerHTML = 'Bắt đầu quét';
    btn.disabled = false;
    showToast('Không thể mở camera: ' + err.message);
  }
}

function stopQrScan() {
  clearInterval(state.qrScanInterval);
  state.qrScanInterval = null;
  if (state.qrStream) {
    state.qrStream.getTracks().forEach(t => t.stop());
    state.qrStream = null;
  }
  $('qr-frame').classList.remove('scanning');
  const btn = $('btn-start-scan');
  btn.innerHTML = `
    <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
      <circle cx="10" cy="10" r="8" stroke="white" stroke-width="2"/>
      <path d="M7 10l2 2 4-4" stroke="white" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
    </svg>
    Bắt đầu quét`;
  btn.disabled = false;
  btn.onclick = startQrScan;
}

function handleQrResult(data) {
  stopQrScan();
  // Accept any QR content as room ID; strip common prefixes if needed
  const roomId = data.trim().replace(/^room[:/]?/i, '').toUpperCase() || data.trim();
  state.roomId = roomId;
  state.photos = [];

  // Update badges
  const label = 'PHÒNG ' + roomId;
  $('camera-room-badge').textContent = label;
  $('report-room-badge').textContent = label;

  goTo('camera');
  startCamera();
}

// ─── CAMERA SCREEN ────────────────────────────────────────────────────────────
async function startCamera() {
  const video = $('camera-video');
  try {
    const stream = await navigator.mediaDevices.getUserMedia({
      video: { facingMode: 'environment', width: { ideal: 1920 }, height: { ideal: 1080 } },
    });
    state.cameraStream = stream;
    video.srcObject = stream;
    await video.play();
  } catch (err) {
    showToast('Không thể mở camera: ' + err.message);
  }
}

function stopCamera() {
  if (state.cameraStream) {
    state.cameraStream.getTracks().forEach(t => t.stop());
    state.cameraStream = null;
  }
}

function capturePhoto() {
  if (state.photos.length >= 3) return;
  const video = $('camera-video');
  const canvas = document.createElement('canvas');
  canvas.width  = video.videoWidth  || 1280;
  canvas.height = video.videoHeight || 720;
  canvas.getContext('2d').drawImage(video, 0, 0);

  canvas.toBlob(blob => {
    const dataUrl = canvas.toDataURL('image/jpeg', 0.85);
    state.photos.push({ blob, dataUrl, s3Url: null });
    updateCameraUI();
  }, 'image/jpeg', 0.85);
}

function deletePhoto(idx) {
  state.photos.splice(idx, 1);
  updateCameraUI();
}

function updateCameraUI() {
  const count = state.photos.length;
  $('photo-count').textContent = count;

  // Thumbnails
  const row = $('thumbnail-row');
  row.innerHTML = state.photos.map((p, i) => `
    <div class="thumb">
      <img src="${p.dataUrl}" alt="Ảnh ${i + 1}">
      <button class="thumb__del" onclick="deletePhoto(${i})" aria-label="Xoá ảnh ${i + 1}">
        <svg width="10" height="10" viewBox="0 0 10 10" fill="none">
          <path d="M2 2l6 6M8 2L2 8" stroke="white" stroke-width="1.8" stroke-linecap="round"/>
        </svg>
      </button>
    </div>
  `).join('');

  // Continue button
  const continueBtn = $('btn-continue-report');
  continueBtn.style.display = count > 0 && count < 3 ? 'flex' : 'none';

  // Auto-advance at 3 photos
  if (count === 3) {
    setTimeout(goToReport, 400);
  }
}

function goToReport() {
  stopCamera();
  renderReportPhotos();
  goTo('report');
}

// ─── REPORT SCREEN ────────────────────────────────────────────────────────────
function renderReportPhotos() {
  const list = $('report-photo-list');
  const count = state.photos.length;
  $('report-photo-count').textContent = count + ' ảnh';
  list.innerHTML = state.photos.map((p, i) => `
    <div class="thumb">
      <img src="${p.dataUrl}" alt="Ảnh ${i + 1}">
    </div>
  `).join('');
}

// Voice recording (Web Speech API)
function initVoice() {
  const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
  if (!SpeechRecognition) {
    $('voice-label').textContent = 'Trình duyệt không hỗ trợ ghi âm';
    $('btn-mic').disabled = true;
    $('transcript-box').style.display = 'block';
    return;
  }
  const recognition = new SpeechRecognition();
  recognition.lang = 'vi-VN';
  recognition.interimResults = true;
  recognition.continuous = true;
  state.recognition = recognition;

  recognition.onstart = () => {
    state.isRecording = true;
    $('btn-mic').classList.add('recording');
    $('voice-label').textContent = 'Đang ghi âm… Nhấn để dừng';
    $('voice-wave').style.display = 'flex';
  };

  recognition.onresult = e => {
    let interim = '';
    let final = state.voiceText;
    for (let i = e.resultIndex; i < e.results.length; i++) {
      if (e.results[i].isFinal) {
        final += e.results[i][0].transcript + ' ';
      } else {
        interim += e.results[i][0].transcript;
      }
    }
    state.voiceText = final;
    const textarea = $('transcript-text');
    textarea.value = final + interim;
    $('transcript-box').style.display = 'block';
  };

  recognition.onend = () => {
    state.isRecording = false;
    $('btn-mic').classList.remove('recording');
    $('voice-label').textContent = state.voiceText ? 'Ghi âm hoàn tất ✓' : 'Nhấn để ghi âm';
    $('voice-wave').style.display = 'none';
    if (state.voiceText) $('transcript-box').style.display = 'block';
  };

  recognition.onerror = e => {
    state.isRecording = false;
    $('btn-mic').classList.remove('recording');
    $('voice-wave').style.display = 'none';
    $('voice-label').textContent = 'Lỗi: ' + e.error + ' – Nhấn thử lại';
  };
}

function toggleVoice() {
  if (!state.recognition) return;
  if (state.isRecording) {
    state.recognition.stop();
  } else {
    state.voiceText = $('transcript-text').value || '';
    state.recognition.start();
  }
}

// Submit report
async function submitReport() {
  const btn = $('btn-submit');
  const errBox = $('submit-error');
  errBox.style.display = 'none';

  if (state.photos.length === 0) {
    errBox.textContent = 'Cần ít nhất 1 ảnh để gửi báo cáo';
    errBox.style.display = 'block';
    return;
  }
  if (!state.roomId) {
    errBox.textContent = 'Thiếu mã phòng';
    errBox.style.display = 'block';
    return;
  }

  btn.disabled = true;
  btn.innerHTML = '<span class="spinner"></span> Đang gửi…';

  try {
    // Upload photos to S3 via presigned URLs
    const imageUrls = await uploadPhotos();

    // Get final voice/note text
    const voiceText = ($('transcript-text').value || '').trim()
      + (($('extra-note').value || '').trim() ? '\n' + $('extra-note').value.trim() : '');

    await api.post('/api/reports', {
      room_id: state.roomId,
      image_urls: imageUrls,
      voice_text: voiceText || null,
    });

    // Show success
    showSuccess(imageUrls.length, !!voiceText);

  } catch (err) {
    errBox.textContent = err.message || 'Gửi thất bại, vui lòng thử lại';
    errBox.style.display = 'block';
    btn.disabled = false;
    btn.innerHTML = `
      <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
        <path d="M3 10l5 5 9-9" stroke="white" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/>
      </svg>
      GỬI BÁO CÁO`;
  }
}

async function uploadPhotos() {
  const urls = [];
  for (let i = 0; i < state.photos.length; i++) {
    const p = state.photos[i];
    if (p.s3Url) { urls.push(p.s3Url); continue; }

    const filename = `housekeeping/${state.roomId}_${Date.now()}_${i}.jpg`;
    const { upload_url, file_url } = await api.post('/api/upload/presigned-url', { filename });
    await fetch(upload_url, {
      method: 'PUT',
      body: p.blob,
      headers: { 'Content-Type': 'image/jpeg' },
    });
    p.s3Url = file_url;
    urls.push(file_url);
  }
  return urls;
}

function showSuccess(photoCount, hasVoice) {
  const now = new Date();
  const timeStr = now.toLocaleString('vi-VN', { hour: '2-digit', minute: '2-digit', day: '2-digit', month: '2-digit', year: 'numeric' });
  $('success-room-text').textContent = 'Phòng ' + state.roomId + ' đã được ghi nhận';
  $('success-time').textContent = timeStr;
  $('success-photos').textContent = photoCount;
  $('success-has-voice').textContent = hasVoice ? '✓' : '–';

  goTo('success');

  // Countdown redirect
  let secs = 3;
  $('countdown').textContent = secs;
  clearTimeout(state.redirectTimer);
  const tick = () => {
    secs--;
    if (secs <= 0) {
      resetApp();
      return;
    }
    $('countdown').textContent = secs;
    state.redirectTimer = setTimeout(tick, 1000);
  };
  state.redirectTimer = setTimeout(tick, 1000);
}

function resetApp() {
  clearTimeout(state.redirectTimer);
  state.roomId   = null;
  state.photos   = [];
  state.voiceText = '';
  state.isRecording = false;
  if (state.recognition) {
    try { state.recognition.abort(); } catch(_) {}
  }

  // Reset transcript
  $('transcript-text').value = '';
  $('transcript-box').style.display = 'none';
  $('extra-note').value = '';
  $('voice-label').textContent = 'Nhấn để ghi âm';
  $('voice-wave').style.display = 'none';
  $('btn-mic').classList.remove('recording');

  // Reset submit btn
  const btn = $('btn-submit');
  btn.disabled = false;
  btn.innerHTML = `
    <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
      <path d="M3 10l5 5 9-9" stroke="white" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/>
    </svg>
    GỬI BÁO CÁO`;

  // Hide all, show qr
  Object.values(screens).forEach(s => {
    s.classList.remove('active', 'slide-out');
    s.style.transform = '';
    s.style.transition = '';
  });
  screens.qr.classList.add('active');
  currentScreen = 'qr';
}

// ─── Init ─────────────────────────────────────────────────────────────────────
document.addEventListener('DOMContentLoaded', () => {
  // QR screen
  $('btn-start-scan').addEventListener('click', startQrScan);

  // Camera screen
  $('btn-back-qr').addEventListener('click', () => {
    stopCamera();
    state.photos = [];
    updateCameraUI();
    goTo('qr', true);
  });
  $('btn-shutter').addEventListener('click', capturePhoto);
  $('btn-continue-report').addEventListener('click', goToReport);

  // Report screen
  $('btn-back-camera').addEventListener('click', () => {
    // Re-open camera when going back
    goTo('camera', true);
    startCamera();
  });
  $('btn-mic').addEventListener('click', toggleVoice);
  $('btn-submit').addEventListener('click', submitReport);

  // Success screen
  $('btn-new-room').addEventListener('click', () => {
    clearTimeout(state.redirectTimer);
    resetApp();
  });

  // Init voice recognition once
  initVoice();
});

